static uint32_t programs_list_calc_total_time_s(uint8_t pid) {
    uint16_t cnt = ui_get_program_steps_total(pid);
    if (cnt > UI_MAX_STEPS) cnt = UI_MAX_STEPS;
    uint32_t total_s = 0;
    int32_t prev_temp = 25;
    for (uint16_t i = 0; i < cnt; i++) {
        int32_t target = (int32_t)ui_get_program_step_temp(pid, i);
        uint16_t rate_x10 = ui_get_program_step_rate_c_per_h_x10(pid, i);
        uint32_t hold_s = ui_get_program_step_hold_s(pid, i);
        if (target == 0) target = ui_program_step_temp_c_fallback(i);
        if (target == 0) target = prev_temp;
        if (rate_x10 == 0) rate_x10 = ui_program_step_rate_c_per_h_x10_fallback(i);
        if (hold_s == 0) hold_s = ui_program_step_hold_s_fallback(i);

        if (rate_x10 > 0) {
            const int32_t diff = (target >= prev_temp) ? (target - prev_temp) : (prev_temp - target);
            total_s += (uint32_t)(((uint32_t)diff * 36000u) / (uint32_t)rate_x10);
        }
        total_s += hold_s;
        prev_temp = target;
    }
    return total_s;
}

