static void ui_program_graph_apply_line_points_scaled(void) {
    if (!s_program_graph_line || !s_program_graph_line_point_count) return;
    if (s_program_graph_line_src_w <= 0 || s_program_graph_line_src_h <= 0) return;

    const lv_coord_t cur_w = lv_obj_get_width(s_program_graph_line);
    const lv_coord_t cur_h = lv_obj_get_height(s_program_graph_line);
    if (cur_w <= 0 || cur_h <= 0) return;

    for (uint32_t i = 0; i < s_program_graph_line_point_count; i++) {
        s_program_graph_line_points[i].x =
            (lv_value_precise_t)(((int32_t)s_program_graph_line_points_src[i].x * (int32_t)cur_w) / (int32_t)s_program_graph_line_src_w);
        s_program_graph_line_points[i].y =
            (lv_value_precise_t)(((int32_t)s_program_graph_line_points_src[i].y * (int32_t)cur_h) / (int32_t)s_program_graph_line_src_h);
    }
    lv_line_set_points_mutable(s_program_graph_line, s_program_graph_line_points, s_program_graph_line_point_count);
}

static bool ui_program_graph_should_show_point_label(uint16_t idx, uint16_t total) {
    if (total <= PROGRAM_GRAPH_MAX_VISIBLE_LABELS) return true;
    if (idx == 0 || idx + 1 == total) return true;

    const uint16_t stride = (uint16_t)((total + (PROGRAM_GRAPH_MAX_VISIBLE_LABELS - 2) - 1) /
                                       (PROGRAM_GRAPH_MAX_VISIBLE_LABELS - 2));
    return (stride > 0) && ((idx % stride) == 0);
}
