static void ui_target_display_size(lv_coord_t *w, lv_coord_t *h) {
    lv_coord_t tw = 800;
    lv_coord_t th = 480;
    lv_display_t *disp = lv_display_get_default();
    if (disp) {
        const lv_coord_t dw = (lv_coord_t)lv_display_get_horizontal_resolution(disp);
        const lv_coord_t dh = (lv_coord_t)lv_display_get_vertical_resolution(disp);
        if (dw > 0) tw = dw;
        if (dh > 0) th = dh;
    }
    if (w) *w = tw;
    if (h) *h = th;
}

typedef struct {
    lv_coord_t sw;
    lv_coord_t sh;
    lv_coord_t margin;
    lv_coord_t gap;
    lv_coord_t header_btn;
    lv_coord_t header_center_y;
    lv_coord_t header_bottom;
    lv_coord_t title_y;
    lv_coord_t title_h;
    lv_coord_t title_w;
    lv_coord_t back_w;
    lv_coord_t toolbar_h;
    lv_coord_t toolbar_y;
    lv_coord_t content_y;
    lv_coord_t content_h;
    lv_coord_t content_w;
    lv_coord_t bottom_h;
    lv_coord_t bottom_y;
} ui_page_layout_t;

static void ui_page_layout_calc(ui_page_layout_t *l) {
    if (!l) return;
    memset(l, 0, sizeof(*l));
    ui_target_display_size(&l->sw, &l->sh);
    if (l->sw < 320) l->sw = 320;
    if (l->sh < 240) l->sh = 240;

    const int32_t zoom_w = ((int32_t)l->sw * 256) / 800;
    const int32_t zoom_h = ((int32_t)l->sh * 256) / 480;
    const int32_t zoom_256 = (zoom_w < zoom_h) ? zoom_w : zoom_h;

    l->margin = (lv_coord_t)LV_MAX(8, ((10 * zoom_256) / 256));
    l->gap = (lv_coord_t)LV_MAX(4, ((8 * zoom_256) / 256));
    l->header_btn = (lv_coord_t)LV_MAX(36, ((56 * zoom_256) / 256));
    l->header_center_y = (lv_coord_t)(l->margin + l->header_btn / 2);
    l->header_bottom = (lv_coord_t)(l->margin + l->header_btn);
    l->title_y = (lv_coord_t)(l->header_bottom + l->gap);
    l->title_h = (lv_coord_t)LV_MAX(18, ((28 * zoom_256) / 256));
    l->title_w = (lv_coord_t)(l->sw - 2 * l->margin - l->gap - LV_MAX((lv_coord_t)90, (lv_coord_t)((110 * zoom_256) / 256)));
    l->back_w = (lv_coord_t)LV_MAX(88, ((110 * zoom_256) / 256));
    l->toolbar_h = (lv_coord_t)LV_MAX(34, ((40 * zoom_256) / 256));
    l->toolbar_y = (lv_coord_t)(l->title_y + l->title_h + l->gap);
    l->content_y = (lv_coord_t)(l->toolbar_y + l->toolbar_h + l->gap);
    l->bottom_h = (lv_coord_t)LV_MAX(34, ((40 * zoom_256) / 256));
    l->bottom_y = (lv_coord_t)(l->sh - l->margin - l->bottom_h);
    l->content_h = (lv_coord_t)(l->bottom_y - l->gap - l->content_y);
    if (l->content_h < 1) l->content_h = 1;
    l->content_w = (lv_coord_t)(l->sw - 2 * l->margin);
}
