#if defined(ESP_PLATFORM)
static uint32_t ui_debug_scan_calendars(lv_obj_t *root, uint32_t node_limit, uint32_t *out_visited, lv_obj_t **out_first) {
    if (out_visited) *out_visited = 0;
    if (out_first) *out_first = NULL;
    if (!root) return 0;

    lv_obj_t *stack[64];
    uint32_t sp = 0;
    stack[sp++] = root;

    uint32_t visited = 0;
    uint32_t count = 0;
    lv_obj_t *first = NULL;

    while (sp > 0 && visited < node_limit) {
        lv_obj_t *obj = stack[--sp];
        if (!obj || !lv_obj_is_valid(obj)) continue;
        visited++;

        if (lv_obj_check_type(obj, &lv_calendar_class)) {
            count++;
            if (!first) first = obj;
        }

        const uint32_t cc = lv_obj_get_child_count(obj);
        for (uint32_t i = 0; i < cc && visited < node_limit && sp < (uint32_t)(sizeof(stack) / sizeof(stack[0])); i++) {
            lv_obj_t *ch = lv_obj_get_child(obj, i);
            if (ch) stack[sp++] = ch;
        }
    }

    if (out_visited) *out_visited = visited;
    if (out_first) *out_first = first;
    return count;
}
#endif
