static void ui_dbg_programs_edit_snapshot(const char *stage) {
    const uint32_t heap_free = esp_get_free_heap_size();
    const uint32_t heap_min = esp_get_minimum_free_heap_size();
    const uint32_t internal_free = heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    const uint32_t internal_largest = heap_caps_get_largest_free_block(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    const uint32_t psram_free = heap_caps_get_free_size(MALLOC_CAP_SPIRAM);
    const uint32_t psram_largest = heap_caps_get_largest_free_block(MALLOC_CAP_SPIRAM);
    const int32_t scroll_y = s_programs_steps_list ? -lv_obj_get_scroll_y(s_programs_steps_list) : -1;
    const uint32_t list_children = s_programs_steps_list ? lv_obj_get_child_count(s_programs_steps_list) : 0;
    const lv_coord_t list_h = s_programs_steps_list ? lv_obj_get_height(s_programs_steps_list) : 0;
    const uint32_t age_ms = s_programs_dbg_entry_ms ? lv_tick_elaps(s_programs_dbg_entry_ms) : 0;

    ESP_LOGI(s_dbg_tag_program_save_time_screens,
             "Programs/Edit %s: age_ms=%lu heap_free=%lu heap_min=%lu free_internal=%lu largest_internal=%lu "
             "free_psram=%lu largest_psram=%lu steps_total=%u steps_built=%u first=%u scroll_y=%ld list_h=%ld "
             "list_children=%lu visible_rows=%u apply_calls=%lu refresh_calls=%lu tick_refresh=%lu "
             "label_updates_last=%lu label_updates_total=%lu",
             stage ? stage : "snapshot", (unsigned long)age_ms, (unsigned long)heap_free, (unsigned long)heap_min,
             (unsigned long)internal_free, (unsigned long)internal_largest, (unsigned long)psram_free,
             (unsigned long)psram_largest, (unsigned)s_programs_steps_total, (unsigned)s_programs_steps_built,
             (unsigned)s_programs_steps_first, (long)scroll_y, (long)list_h, (unsigned long)list_children,
             (unsigned)s_programs_dbg_last_visible_rows, (unsigned long)s_programs_dbg_apply_calls,
             (unsigned long)s_programs_dbg_refresh_calls, (unsigned long)s_programs_dbg_tick_refresh_calls,
             (unsigned long)s_programs_dbg_last_apply_label_updates, (unsigned long)s_programs_dbg_label_updates_total);
}
#endif
// #endregion

static void ui_copy_utf8_trunc(char *dst, size_t dst_sz, const char *src) {
    if (!dst || dst_sz == 0) return;
    if (!src) src = "";
    size_t n = 0;
    while (src[n] != '\0' && n + 1 < dst_sz) {
        dst[n] = src[n];
        n++;
    }
    dst[n] = '\0';
    if (n == 0) return;

    size_t start = n;
    while (start > 0 && (((unsigned char)dst[start - 1] & 0xC0U) == 0x80U)) {
        start--;
    }
    if (start == n) return;

    const unsigned char lead = (unsigned char)dst[start];
    size_t need = 1;
    if ((lead & 0x80U) == 0x00U) need = 1;
    else if ((lead & 0xE0U) == 0xC0U) need = 2;
    else if ((lead & 0xF0U) == 0xE0U) need = 3;
    else if ((lead & 0xF8U) == 0xF0U) need = 4;
    else {
        dst[start] = '\0';
        return;
    }
    if (n - start < need) dst[start] = '\0';
}

