static void ui_settings_update_info_text(void) {
    if (!s_settings_info_root) return;

    char buf[128];
    char buf2[96];

    buf[0] = '\0';
    buf2[0] = '\0';

#if defined(ESP_PLATFORM)
    const esp_app_desc_t *app = esp_app_get_description();
    esp_chip_info_t ci;
    esp_chip_info(&ci);

    const uint32_t heap_free = heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    const uint32_t heap_total = heap_caps_get_total_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    const uint32_t heap_min = esp_get_minimum_free_heap_size();
    const uint32_t psram_free = heap_caps_get_free_size(MALLOC_CAP_SPIRAM);
    const uint32_t psram_total = heap_caps_get_total_size(MALLOC_CAP_SPIRAM);

    size_t fs_total = 0;
    size_t fs_used = 0;
    const esp_err_t fs_err = esp_littlefs_info("storage", &fs_total, &fs_used);
    const uint32_t uptime_s = (uint32_t)(esp_timer_get_time() / 1000000ULL);
    const uint32_t up_h = uptime_s / 3600U;
    const uint32_t up_m = (uptime_s % 3600U) / 60U;
    const uint32_t up_sec = uptime_s % 60U;

    const int tc = kiln_ui_get_thermocouple_status();
    const char *tc_txt_en = "OK";
    const char *tc_txt_ua = "OK";
    if (tc == 1) {
        tc_txt_en = "OPEN / NOT CONNECTED";
        tc_txt_ua = "ОБРИВ / НЕ ПІДКЛЮЧЕНА";
    } else if (tc == 2) {
        tc_txt_en = "SHORT";
        tc_txt_ua = "КОРОТКЕ ЗАМИКАННЯ";
    } else if (tc == 3) {
        tc_txt_en = "NO DATA";
        tc_txt_ua = "НЕМАЄ ДАНИХ";
    } else if (tc != 0) {
        tc_txt_en = "FAULT";
        tc_txt_ua = "ПОМИЛКА";
    }

    lv_snprintf(buf, sizeof(buf), "%s",
                (app && app->version[0]) ? app->version : "N/A");
    ui_settings_set_label_text_if_changed(s_settings_info_fw_value, buf);

    lv_snprintf(buf, sizeof(buf), "%s",
                (app && app->idf_ver[0]) ? app->idf_ver : esp_get_idf_version());
    ui_settings_set_label_text_if_changed(s_settings_info_idf_value, buf);

    lv_snprintf(buf, sizeof(buf), "ESP32-S3 rev %u, %u core%s",
                (unsigned)ci.revision, (unsigned)ci.cores, (ci.cores == 1U) ? "" : "s");
    ui_settings_set_label_text_if_changed(s_settings_info_chip_value, buf);

    lv_snprintf(buf, sizeof(buf), "%02u:%02u:%02u", (unsigned)up_h, (unsigned)up_m, (unsigned)up_sec);
    ui_settings_set_label_text_if_changed(s_settings_info_uptime_value, buf);

    const uint32_t heap_used = (heap_total > heap_free) ? (heap_total - heap_free) : 0;
    const int32_t heap_pct = (heap_total > 0U) ? (int32_t)((heap_used * 100U) / heap_total) : 0;
    lv_snprintf(buf, sizeof(buf), "%s: %u / %u KB",
                ui_is_english() ? "RAM used" : "RAM зайнято",
                (unsigned)(heap_used / 1024U), (unsigned)(heap_total / 1024U));
    ui_settings_set_label_text_if_changed(s_settings_info_ram_text, buf);
    lv_snprintf(buf2, sizeof(buf2), "%s: %u KB", ui_is_english() ? "Free" : "Вільно", (unsigned)(heap_free / 1024U));
    ui_settings_set_label_text_if_changed(s_settings_info_ram_free_value, buf2);
    ui_settings_set_bar_value_if_changed(s_settings_info_ram_bar, heap_pct);

    const uint32_t psram_used = (psram_total > psram_free) ? (psram_total - psram_free) : 0;
    const int32_t psram_pct = (psram_total > 0U) ? (int32_t)((psram_used * 100U) / psram_total) : 0;
    lv_snprintf(buf, sizeof(buf), "%s: %u / %u KB",
                ui_is_english() ? "PSRAM used" : "PSRAM зайнято",
                (unsigned)(psram_used / 1024U), (unsigned)(psram_total / 1024U));
    ui_settings_set_label_text_if_changed(s_settings_info_psram_text, buf);
    lv_snprintf(buf2, sizeof(buf2), "%s: %u KB", ui_is_english() ? "Free" : "Вільно", (unsigned)(psram_free / 1024U));
    ui_settings_set_label_text_if_changed(s_settings_info_psram_free_value, buf2);
    ui_settings_set_bar_value_if_changed(s_settings_info_psram_bar, psram_pct);

    if (fs_err == ESP_OK) {
        const size_t free_b = (fs_total > fs_used) ? (fs_total - fs_used) : 0;
        const int32_t fs_pct = (fs_total > 0U) ? (int32_t)((fs_used * 100U) / fs_total) : 0;
        lv_snprintf(buf, sizeof(buf), "%s: %u / %u KB",
                    ui_is_english() ? "Storage used" : "Storage зайнято",
                    (unsigned)(fs_used / 1024U), (unsigned)(fs_total / 1024U));
        ui_settings_set_label_text_if_changed(s_settings_info_storage_text, buf);
        lv_snprintf(buf2, sizeof(buf2), "%s: %u KB", ui_is_english() ? "Free" : "Вільно", (unsigned)(free_b / 1024U));
        ui_settings_set_label_text_if_changed(s_settings_info_storage_free_value, buf2);
        ui_settings_set_bar_value_if_changed(s_settings_info_storage_bar, fs_pct);
    } else {
        ui_settings_set_label_text_if_changed(s_settings_info_storage_text, ui_is_english() ? "Storage: N/A" : "Storage: недоступно");
        ui_settings_set_label_text_if_changed(s_settings_info_storage_free_value, "");
        ui_settings_set_bar_value_if_changed(s_settings_info_storage_bar, 0);
    }

    lv_snprintf(buf, sizeof(buf), "MAX31855 (%s)", ui_is_english() ? tc_txt_en : tc_txt_ua);
    ui_settings_set_label_text_if_changed(s_settings_info_tc_value, buf);

    lv_snprintf(buf, sizeof(buf), "%s: %u KB",
                ui_is_english() ? "Minimum free heap" : "Мін. вільна RAM",
                (unsigned)(heap_min / 1024U));
    ui_settings_set_label_text_if_changed(s_settings_info_heap_min_value, buf);
#else
    ui_settings_set_label_text_if_changed(s_settings_info_fw_value, "N/A");
    ui_settings_set_label_text_if_changed(s_settings_info_idf_value, "N/A");
    ui_settings_set_label_text_if_changed(s_settings_info_chip_value, "ESP32-S3");
    ui_settings_set_label_text_if_changed(s_settings_info_uptime_value, "--:--:--");
    ui_settings_set_label_text_if_changed(s_settings_info_ram_text, ui_is_english() ? "RAM: available on device" : "RAM: доступно на пристрої");
    ui_settings_set_label_text_if_changed(s_settings_info_ram_free_value, "");
    ui_settings_set_label_text_if_changed(s_settings_info_psram_text, ui_is_english() ? "PSRAM: available on device" : "PSRAM: доступно на пристрої");
    ui_settings_set_label_text_if_changed(s_settings_info_psram_free_value, "");
    ui_settings_set_label_text_if_changed(s_settings_info_storage_text, ui_is_english() ? "Storage: available on device" : "Storage: доступно на пристрої");
    ui_settings_set_label_text_if_changed(s_settings_info_storage_free_value, "");
    ui_settings_set_bar_value_if_changed(s_settings_info_ram_bar, 0);
    ui_settings_set_bar_value_if_changed(s_settings_info_psram_bar, 0);
    ui_settings_set_bar_value_if_changed(s_settings_info_storage_bar, 0);
    ui_settings_set_label_text_if_changed(s_settings_info_tc_value, ui_is_english() ? "Available on device" : "Доступно на пристрої");
    ui_settings_set_label_text_if_changed(s_settings_info_heap_min_value, "");
#endif
}

