static void ui_update_current_temp(lv_obj_t *value_lbl, lv_obj_t *unit_lbl, lv_obj_t *line_lbl, uint32_t *last_update_ms,
                                   char *last_text, size_t last_text_sz, bool *last_error) {
    if (!value_lbl) return;

    const uint32_t now = lv_tick_get();
    if (*last_update_ms != 0 && (uint32_t)(now - *last_update_ms) < 1000U) return;
    *last_update_ms = now;

    const float t_c = ui_get_kiln_current_temp_c();
    char buf[16];
    buf[0] = '\0';

    int tc_status = 0;
    bool sensor_invalid = false;
    bool fault_active = false;
    uint32_t fault_code = 0;
    char fault_reason[96];
    fault_reason[0] = '\0';
#if defined(ESP_PLATFORM)
    tc_status = kiln_ui_get_thermocouple_status();
    sensor_invalid = (tc_status != 0);
    fault_active = (kiln_ui_fault_is_active() != 0);
    fault_code = kiln_ui_fault_code();
    (void)kiln_ui_fault_reason(fault_reason, (int)sizeof(fault_reason));
#endif
    if (fault_code == 0U) {
        if (tc_status == 1) fault_code = 7U;
        else if (tc_status == 2) fault_code = 8U;
        else if (tc_status == 3 || tc_status == 4) fault_code = 2U;
    }

    const bool is_nan = !(t_c == t_c);
    const bool is_error = (fault_active || sensor_invalid || is_nan || t_c < -100.0f || t_c > 2000.0f);
    if (is_error) {
        if (fault_code != 0U) ui_fault_code_short_text(buf, sizeof(buf), fault_code);
        else lv_snprintf(buf, sizeof(buf), "--");
        if (unit_lbl) {
            const char *t = lv_label_get_text(unit_lbl);
            if (!t || t[0] != '\0') lv_label_set_text(unit_lbl, "");
        }
        if (line_lbl) {
            lv_obj_clear_flag(line_lbl, LV_OBJ_FLAG_HIDDEN);
            const char *msg = (fault_reason[0])
                                  ? fault_reason
                                  : (ui_is_english() ? "Thermocouple not connected" : "Термопара не підключена");
            const char *t = lv_label_get_text(line_lbl);
            if (!t || strcmp(t, msg) != 0) lv_label_set_text(line_lbl, msg);
        }
    } else {
        const float t = ui_temp_to_display(t_c);
        const float abs_t = (t < 0.0f) ? -t : t;
        const bool with_decimal = (abs_t < 100.0f);
        const int32_t t10 = (int32_t)((t >= 0.0f) ? (t * 10.0f + 0.5f) : (t * 10.0f - 0.5f));
        if (with_decimal) {
            const int32_t whole = t10 / 10;
            int32_t frac = t10 % 10;
            if (frac < 0) frac = -frac;
            lv_snprintf(buf, sizeof(buf), ui_is_english() ? "%ld.%ld" : "%ld,%ld", (long)whole, (long)frac);
        } else {
            const int32_t whole = (int32_t)((t >= 0.0f) ? (t + 0.5f) : (t - 0.5f));
            lv_snprintf(buf, sizeof(buf), "%ld", (long)whole);
        }
        if (unit_lbl) {
            const char *unit = ui_temp_unit_text_short();
            const char *t = lv_label_get_text(unit_lbl);
            if (!t || strcmp(t, unit) != 0) lv_label_set_text(unit_lbl, unit);
        }
        if (line_lbl) {
            if (!lv_obj_has_flag(line_lbl, LV_OBJ_FLAG_HIDDEN)) lv_obj_add_flag(line_lbl, LV_OBJ_FLAG_HIDDEN);
            const char *t = lv_label_get_text(line_lbl);
            if (t && t[0] != '\0') lv_label_set_text(line_lbl, "");
        }
    }

    if (line_lbl) {
        if (!lv_obj_has_flag(line_lbl, LV_OBJ_FLAG_USER_3)) {
            lv_obj_set_width(line_lbl, 355);
            lv_label_set_long_mode(line_lbl, LV_LABEL_LONG_CLIP);
            lv_obj_set_style_text_align(line_lbl, LV_TEXT_ALIGN_LEFT, LV_PART_MAIN | LV_STATE_DEFAULT);
            lv_obj_add_flag(line_lbl, LV_OBJ_FLAG_USER_3);
        }
    }
    if (line_lbl && last_error && (*last_error != is_error)) {
        if (is_error) {
            lv_obj_set_pos(line_lbl, 15, 170);
            lv_obj_set_style_text_color(line_lbl, lv_color_hex(0xffff3b30), LV_PART_MAIN | LV_STATE_DEFAULT);
            lv_obj_set_style_text_font(line_lbl, &font_4305a60a491c803d80080d0276f8a0f7, LV_PART_MAIN | LV_STATE_DEFAULT);
        } else {
            lv_obj_set_pos(line_lbl, 15, 230);
            lv_obj_set_style_text_color(line_lbl, lv_color_hex(0xff00b761), LV_PART_MAIN | LV_STATE_DEFAULT);
            lv_obj_set_style_text_font(line_lbl, &font_4305a60a491c803d80080d0337447350, LV_PART_MAIN | LV_STATE_DEFAULT);
        }
    }
    if (last_error) *last_error = is_error;

    if (strncmp(last_text, buf, last_text_sz) != 0) {
        strncpy(last_text, buf, last_text_sz - 1);
        last_text[last_text_sz - 1] = '\0';
        lv_label_set_text(value_lbl, last_text);
    }
}

static int16_t ui_program_step_temp_c_fallback(uint16_t idx) {
    if (idx == 0) return 200;
    if (idx == 1) return 600;
    if (idx == 2) return 900;
    return 1100;
}

static uint16_t ui_program_step_rate_c_per_h_x10_fallback(uint16_t idx) {
    if (idx == 0) return 1500;
    if (idx == 1) return 2000;
    if (idx == 2) return 1800;
    return 1500;
}

static uint32_t ui_program_step_hold_s_fallback(uint16_t idx) {
    if (idx == 0) return 600;
    if (idx == 1) return 1200;
    if (idx == 2) return 900;
    return 1200;
}

static uint16_t ui_selected_program_max_temp_c_fallback(void) {
    const uint8_t pid = ui_get_selected_program_id();
    if (pid == 255 || pid >= ui_get_program_count()) return 0;
    uint16_t steps = ui_get_program_steps_total(pid);
    if (steps < 1) steps = 1;
    if (steps > 50) steps = 50;

    uint16_t max_c = 0;
    for (uint16_t i = 0; i < steps; i++) {
        int16_t t = ui_get_program_step_temp(pid, i);
        if (t == 0) t = ui_program_step_temp_c_fallback(i);
        if (t > 0 && (uint16_t)t > max_c) max_c = (uint16_t)t;
    }
    return max_c;
}

static uint16_t ui_selected_program_first_temp_c_fallback(void) {
    const uint8_t pid = ui_get_selected_program_id();
    if (pid != 255 && pid >= ui_get_program_count()) return 0;
    int16_t t = ui_get_program_step_temp(pid, 0);
    if (t == 0) t = ui_program_step_temp_c_fallback(0);
    if (t <= 0) return 0;
    return (uint16_t)t;
}

static uint16_t ui_selected_program_first_rate_c_per_h_x10_fallback(void) {
    const uint8_t pid = ui_get_selected_program_id();
    if (pid != 255 && pid >= ui_get_program_count()) return 0;
    uint16_t rate_x10 = ui_get_program_step_rate_c_per_h_x10(pid, 0);
    if (rate_x10 == 0) rate_x10 = ui_program_step_rate_c_per_h_x10_fallback(0);
    return rate_x10;
}

static bool ui_selected_program_get_display_step(uint16_t *out_step_idx, uint16_t *out_target_c, uint16_t *out_rate_x10) {
    uint8_t pid = ui_get_selected_program_id();
    const uint8_t count = ui_get_program_count();
    if (pid != 255 && pid >= count) {
        if (count == 0) return false;
        pid = 0;
    }
    if (pid == 255 && count == 0) return false;

    uint16_t steps = ui_get_program_steps_total(pid);
    if (steps < 1) steps = 1;
    if (steps > UI_MAX_STEPS) steps = UI_MAX_STEPS;

    uint16_t step_idx = 0;
    if (ui_kiln_is_firing()) {
        const int runtime_step = ui_kiln_current_step();
        if (runtime_step >= 0) {
            int runtime_idx = 0;
            for (uint16_t i = 0; i < steps; i++) {
                if (runtime_idx == runtime_step) {
                    step_idx = i;
                    break;
                }
                runtime_idx++;
                if (ui_get_program_step_hold_s(pid, i) > 0) {
                    if (runtime_idx == runtime_step) {
                        step_idx = i;
                        break;
                    }
                    runtime_idx++;
                }
                step_idx = i;
            }
        }
    }

    int16_t temp_c = ui_get_program_step_temp(pid, step_idx);
    if (temp_c == 0) temp_c = ui_program_step_temp_c_fallback(step_idx);
    uint16_t rate_x10 = ui_get_program_step_rate_c_per_h_x10(pid, step_idx);
    if (rate_x10 == 0) rate_x10 = ui_program_step_rate_c_per_h_x10_fallback(step_idx);

    if (out_step_idx) *out_step_idx = step_idx;
    if (out_target_c) *out_target_c = (temp_c > 0) ? (uint16_t)temp_c : 0;
    if (out_rate_x10) *out_rate_x10 = rate_x10;
    return true;
}

static void ui_update_target_and_rate(lv_obj_t *target_lbl, lv_obj_t *rate_lbl, lv_obj_t *progress_bar, uint32_t *last_update_ms,
                                      char *last_target, size_t last_target_sz, char *last_rate, size_t last_rate_sz) {
    const uint32_t now = lv_tick_get();
    if (*last_update_ms != 0 && (uint32_t)(now - *last_update_ms) < 1000U) return;
    *last_update_ms = now;

    char target_buf[16];
    target_buf[0] = '\0';

    float target_final_c = 0.0f;
    float rate_c_per_min = 0.0f;
    float step_start_temp_c = 0.0f;
    int step_type = -1;
    const bool is_firing = ui_kiln_is_firing();
    uint16_t selected_step_idx = 0;
    uint16_t selected_target_c = 0;
    uint16_t selected_rate_x10 = 0;
    const bool have_selected_step =
        ui_selected_program_get_display_step(&selected_step_idx, &selected_target_c, &selected_rate_x10);
    if (have_selected_step && selected_target_c > 0) {
        target_final_c = (float)selected_target_c;
        lv_snprintf(target_buf, sizeof(target_buf), "%d", ui_temp_display_from_c_int((int)selected_target_c));
    } else {
        lv_snprintf(target_buf, sizeof(target_buf), "--");
    }

    char rate_buf[24];
    rate_buf[0] = '\0';
    const uint16_t rate_x10 = have_selected_step ? selected_rate_x10 : 0;
    if (rate_x10 == 0) {
        lv_snprintf(rate_buf, sizeof(rate_buf), "--");
    } else {
        const uint16_t disp_x10 = ui_rate_display_from_c_per_h_x10(rate_x10);
        if ((disp_x10 % 10) == 0) {
            lv_snprintf(rate_buf, sizeof(rate_buf), "%u", (unsigned)(disp_x10 / 10));
        } else {
            lv_snprintf(rate_buf, sizeof(rate_buf), "%u.%u", (unsigned)(disp_x10 / 10), (unsigned)(disp_x10 % 10));
        }
    }

    if (is_firing) {
        if (ui_kiln_get_active_step_info(&step_type, NULL, &rate_c_per_min, &step_start_temp_c)) {
            if (step_type != 0) {
                rate_c_per_min = 0.0f;
            }
        } else {
            step_type = -1;
        }
    }

    if (progress_bar) {
        int16_t v = 0;
        if (is_firing && step_type >= 0) {
            if (step_type != 0) {
                v = 100;
            } else {
                const float cur_c = ui_get_kiln_current_temp_c();
                const float start_c = step_start_temp_c;
                const float dst = target_final_c - start_c;
                const float abs_dst = (dst < 0.0f) ? -dst : dst;
                if (!(cur_c == cur_c) || !(start_c == start_c) || !(target_final_c == target_final_c) || abs_dst < 0.5f) {
                    v = 100;
                } else if (dst > 0.0f) {
                    float p = ((cur_c - start_c) / dst) * 100.0f;
                    if (p < 0.0f) p = 0.0f;
                    if (p > 100.0f) p = 100.0f;
                    v = (int16_t)(p + 0.5f);
                } else {
                    float p = ((start_c - cur_c) / abs_dst) * 100.0f;
                    if (p < 0.0f) p = 0.0f;
                    if (p > 100.0f) p = 100.0f;
                    v = (int16_t)(p + 0.5f);
                }
            }
        }
        if (v < 0) v = 0;
        if (v > 100) v = 100;
        lv_bar_set_value(progress_bar, v, LV_ANIM_OFF);
    }

    if (target_lbl) {
        lv_obj_clear_flag(target_lbl, LV_OBJ_FLAG_HIDDEN);
        lv_obj_set_style_text_opa(target_lbl, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_color(target_lbl, lv_color_hex(0xff00b761), LV_PART_MAIN | LV_STATE_DEFAULT);
    }
    if (rate_lbl) {
        lv_obj_clear_flag(rate_lbl, LV_OBJ_FLAG_HIDDEN);
        lv_obj_set_style_text_opa(rate_lbl, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_color(rate_lbl, lv_color_hex(0xffffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
    }

#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_target_rate,
             "target_rate: firing=%d sel_id=%u sel_name='%s' ui_step=%u have_step=%d step_idx=%u step_type=%d runtime_step=%d runtime_total=%d target_c=%u rate_x10=%u target_txt='%s' rate_txt='%s' target_lbl=%p rate_lbl=%p",
             is_firing ? 1 : 0, (unsigned)ui_get_selected_program_id(), ui_get_selected_program_name(),
             (unsigned)ui_get_selected_program_steps_total(), have_selected_step ? 1 : 0, (unsigned)selected_step_idx,
             step_type, ui_kiln_current_step(), ui_kiln_total_steps(), (unsigned)selected_target_c, (unsigned)selected_rate_x10,
             target_buf, rate_buf, (void *)target_lbl, (void *)rate_lbl);
#endif

    if (target_lbl && strncmp(last_target, target_buf, last_target_sz) != 0) {
        strncpy(last_target, target_buf, last_target_sz - 1);
        last_target[last_target_sz - 1] = '\0';
        lv_label_set_text(target_lbl, last_target);
    }
    if (rate_lbl && strncmp(last_rate, rate_buf, last_rate_sz) != 0) {
        strncpy(last_rate, rate_buf, last_rate_sz - 1);
        last_rate[last_rate_sz - 1] = '\0';
        lv_label_set_text(rate_lbl, last_rate);
    }
}

