static void ui_settings_sync_title(void) {
    if (!s_settings_title_lbl) return;
    lv_label_set_text(s_settings_title_lbl,
                      s_settings_section_open ? ui_settings_section_title(s_settings_menu_selected)
                                              : (ui_is_english() ? "SETTINGS" : "НАЛАШТУВАННЯ"));
}

static uint32_t ui_fault_code_from_log_msg(const char *msg) {
    if (!msg) return 0;
    const char *p = strstr(msg, "code=");
    if (!p) return 0;
    p += 5;
    return (uint32_t)strtoul(p, NULL, 10);
}

static void ui_fault_reason_from_log_msg(const char *msg, char *out, size_t out_sz) {
    if (!out || out_sz == 0) return;
    out[0] = 0;
    if (!msg) return;
    const char *p = strstr(msg, "reason=");
    if (!p) {
        strncpy(out, msg, out_sz - 1);
        out[out_sz - 1] = 0;
        return;
    }
    p += 7;
    strncpy(out, p, out_sz - 1);
    out[out_sz - 1] = 0;
}

static void ui_format_error_log_timestamp(uint64_t uptime_ms, uint64_t unix_s, char *out, size_t out_sz) {
    if (!out || out_sz == 0) return;
    out[0] = 0;

    if (unix_s >= 1704067200ULL) {
        time_t ts = (time_t)unix_s;
        struct tm tmv;
#if defined(ESP_PLATFORM)
        localtime_r(&ts, &tmv);
#else
        struct tm *ptm = localtime(&ts);
        if (!ptm) {
            tmv = (struct tm){0};
        } else {
            tmv = *ptm;
        }
#endif
        char date_buf[40];
        const char *date_fmt = "%d.%m.%Y";
        const char *time_fmt = "%H:%M:%S";
        switch (ui_get_date_format()) {
            case UI_DATE_FORMAT_MMDDYYYY: date_fmt = "%m.%d.%Y"; break;
            case UI_DATE_FORMAT_YYYYMMDD: date_fmt = "%Y-%m-%d"; break;
            case UI_DATE_FORMAT_DDMMYYYY:
            default: date_fmt = "%d.%m.%Y"; break;
        }
        if (ui_get_time_format() == UI_TIME_FORMAT_12H) time_fmt = "%I:%M:%S %p";
        char fmt[40];
        lv_snprintf(fmt, sizeof(fmt), "%s %s", date_fmt, time_fmt);
        strftime(date_buf, sizeof(date_buf), fmt, &tmv);
        strncpy(out, date_buf, out_sz - 1);
        out[out_sz - 1] = 0;
        return;
    }

    const uint32_t total_s = (uint32_t)(uptime_ms / 1000ULL);
    const uint32_t h = total_s / 3600U;
    const uint32_t m = (total_s / 60U) % 60U;
    const uint32_t s = total_s % 60U;
    lv_snprintf(out, out_sz, "%s %02u:%02u:%02u",
                ui_is_english() ? "Uptime" : "Аптайм",
                (unsigned)h, (unsigned)m, (unsigned)s);
}

static void ui_settings_update_errors_text(void) {
    if (!s_settings_errors_root) return;

    const bool en = ui_is_english();
    int active = 0;
    int tc_status = 0;
    uint32_t code = 0;
    uint32_t age_s = 0;
    char reason[96];
    reason[0] = 0;

#if defined(ESP_PLATFORM)
    active = kiln_ui_fault_is_active();
    tc_status = kiln_ui_get_thermocouple_status();
    code = kiln_ui_fault_code();
    const uint64_t since_ms = kiln_ui_fault_since_ms();
    const uint64_t now_ms = (uint64_t)(esp_timer_get_time() / 1000ULL);
    if (since_ms != 0 && now_ms > since_ms) {
        age_s = (uint32_t)((now_ms - since_ms) / 1000ULL);
    }
    (void)kiln_ui_fault_reason(reason, (int)sizeof(reason));
#else
    active = 0;
    tc_status = 0;
    code = 0;
    age_s = 0;
    strncpy(reason, "N/A", sizeof(reason) - 1);
    reason[sizeof(reason) - 1] = 0;
#endif

    if (!active && tc_status != 0) {
        active = 1;
    }
    if (code == 0U) {
        if (tc_status == 1) code = 7U;
        else if (tc_status == 2) code = 8U;
        else if (tc_status == 3 || tc_status == 4) code = 2U;
    }
    if (reason[0] == '\0' && code != 0U) {
        lv_snprintf(reason, sizeof(reason), "%s", ui_fault_code_text(code));
    }

    const bool state_changed =
        (active != s_settings_errors_cache_active) ||
        (tc_status != s_settings_errors_cache_tc_status) ||
        (code != s_settings_errors_cache_code) ||
        (age_s != s_settings_errors_cache_age_s) ||
        (strcmp(reason, s_settings_errors_cache_reason) != 0);

#if defined(ESP_PLATFORM)
    // #region debug-point settings-history-panic-errors-state
    if (state_changed) {
        ESP_LOGI(s_dbg_tag_settings_freeze,
                 "errors_state: active=%d tc_status=%d code=%u age_s=%u reason='%s' root=%p status=%p act=%p cur=%d sel=%u",
                 active,
                 tc_status,
                 (unsigned)code,
                 (unsigned)age_s,
                 reason,
                 (void *)s_settings_errors_root,
                 (void *)s_settings_errors_status_value,
                 (void *)lv_scr_act(),
                 (int)ui_get_current_screen_id(),
                 (unsigned)s_settings_menu_selected);
    }
    // #endregion
#endif

    if (!state_changed) {
        if (s_settings_errors_action_msg) {
            const uint32_t now = lv_tick_get();
            if (s_settings_errors_action_until_ms != 0 && (uint32_t)(now - s_settings_errors_action_until_ms) < 0x80000000U) {
                lv_obj_add_flag(s_settings_errors_action_msg, LV_OBJ_FLAG_HIDDEN);
                s_settings_errors_action_until_ms = 0;
            }
        }
        return;
    }

    char status_buf[64];
    if (active) lv_snprintf(status_buf, sizeof(status_buf), "%s (%us)", en ? "Fault active" : "Помилка активна", (unsigned)age_s);
    else lv_snprintf(status_buf, sizeof(status_buf), "%s", en ? "No faults" : "Нема помилок");

    const char *src_txt = ui_fault_source_text(code);
    char code_buf[96];
    lv_snprintf(code_buf, sizeof(code_buf), "%s (#%u)", ui_fault_code_text(code), (unsigned)code);

    if (s_settings_errors_status_value) {
        const char *cur = lv_label_get_text(s_settings_errors_status_value);
        if (!cur || strcmp(cur, status_buf) != 0) lv_label_set_text(s_settings_errors_status_value, status_buf);
    }
    if (s_settings_errors_source_value) {
        const char *cur = lv_label_get_text(s_settings_errors_source_value);
        if (!cur || strcmp(cur, src_txt) != 0) lv_label_set_text(s_settings_errors_source_value, src_txt);
    }
    if (s_settings_errors_code_value) {
        const char *cur = lv_label_get_text(s_settings_errors_code_value);
        if (!cur || strcmp(cur, code_buf) != 0) lv_label_set_text(s_settings_errors_code_value, code_buf);
    }
    if (s_settings_errors_reason_value) {
        const char *txt = active ? (reason[0] ? reason : (en ? "No details" : "Нема деталей")) : (en ? "OK" : "OK");
        const char *cur = lv_label_get_text(s_settings_errors_reason_value);
        if (!cur || strcmp(cur, txt) != 0) lv_label_set_text(s_settings_errors_reason_value, txt);
    }
    if (s_settings_errors_reset_btn) {
        if (active) lv_obj_clear_state(s_settings_errors_reset_btn, LV_STATE_DISABLED);
        else lv_obj_add_state(s_settings_errors_reset_btn, LV_STATE_DISABLED);
    }
    s_settings_errors_cache_active = active;
    s_settings_errors_cache_tc_status = tc_status;
    s_settings_errors_cache_code = code;
    s_settings_errors_cache_age_s = age_s;
    strncpy(s_settings_errors_cache_reason, reason, sizeof(s_settings_errors_cache_reason) - 1);
    s_settings_errors_cache_reason[sizeof(s_settings_errors_cache_reason) - 1] = 0;
    if (s_settings_errors_action_msg) {
        const uint32_t now = lv_tick_get();
        if (s_settings_errors_action_until_ms != 0 && (uint32_t)(now - s_settings_errors_action_until_ms) < 0x80000000U) {
            lv_obj_add_flag(s_settings_errors_action_msg, LV_OBJ_FLAG_HIDDEN);
            s_settings_errors_action_until_ms = 0;
        }
    }
}

#if defined(ESP_PLATFORM)
static char *ui_read_file_tail_alloc(const char *path, size_t max_bytes, size_t *out_len) {
    if (out_len) *out_len = 0;
    if (!path || !path[0]) return NULL;
    if (max_bytes < 256) max_bytes = 256;

    const int fd = open(path, O_RDONLY, 0);
    if (fd < 0) return NULL;

    struct stat st;
    memset(&st, 0, sizeof(st));
    if (fstat(fd, &st) != 0 || st.st_size <= 0) {
        close(fd);
        return NULL;
    }

    size_t sz = (size_t)st.st_size;
    size_t rd_sz = (sz > max_bytes) ? max_bytes : sz;
    off_t start = (off_t)(st.st_size - (off_t)rd_sz);
    if (start < 0) start = 0;
    if (lseek(fd, start, SEEK_SET) < 0) {
        close(fd);
        return NULL;
    }

    char *buf = (char *)ui_psram_calloc_fallback(rd_sz + 1, 1);
    if (!buf) {
        close(fd);
        return NULL;
    }

    size_t off = 0;
    while (off < rd_sz) {
        const ssize_t r = read(fd, buf + off, rd_sz - off);
        if (r <= 0) break;
        off += (size_t)r;
    }
    close(fd);

    if (off == 0) {
        free(buf);
        return NULL;
    }
    buf[off] = '\0';
    if (out_len) *out_len = off;
    return buf;
}
#endif

static lv_coord_t ui_settings_errors_row_h(void) {
    return 64;
}

static void ui_settings_errors_refresh_table(void) {
    if (!s_settings_errors_log_list || !s_settings_errors_log_table || !lv_obj_is_valid(s_settings_errors_log_list)) return;

    const uint16_t max_first = (s_settings_errors_entries_count > SETTINGS_ERRORS_VISIBLE_ROWS)
                                   ? (uint16_t)(s_settings_errors_entries_count - SETTINGS_ERRORS_VISIBLE_ROWS)
                                   : 0;
    if (s_settings_errors_log_first > max_first) {
        s_settings_errors_log_first = max_first;
    }

    if (s_settings_errors_log_text) {
        if (s_settings_errors_entries_count == 0) {
            lv_obj_clear_flag(s_settings_errors_log_text, LV_OBJ_FLAG_HIDDEN);
        } else {
            lv_obj_add_flag(s_settings_errors_log_text, LV_OBJ_FLAG_HIDDEN);
        }
    }

    const lv_coord_t row_h = ui_settings_errors_row_h();
    int32_t content_h = (int32_t)s_settings_errors_entries_count * (int32_t)row_h;
    if (content_h < 1) content_h = 1;
    if (s_settings_errors_log_spacer) {
        lv_obj_set_size(s_settings_errors_log_spacer, lv_pct(100), (lv_coord_t)content_h);
    }

    lv_coord_t content_w = lv_obj_get_content_width(s_settings_errors_log_list);
    if (content_w < 260) content_w = 260;
    lv_obj_set_width(s_settings_errors_log_table, content_w);
    lv_obj_set_height(s_settings_errors_log_table, (lv_coord_t)(SETTINGS_ERRORS_VISIBLE_ROWS * row_h));
    lv_table_set_column_width(s_settings_errors_log_table, 0, 110);
    lv_table_set_column_width(s_settings_errors_log_table, 1, 120);
    lv_table_set_column_width(s_settings_errors_log_table, 2, 90);
    lv_table_set_column_width(s_settings_errors_log_table, 3, (uint32_t)LV_MAX(120, content_w - 320));

    for (uint16_t slot = 0; slot < SETTINGS_ERRORS_VISIBLE_ROWS; slot++) {
        const uint16_t idx = (uint16_t)(s_settings_errors_log_first + slot);
        if (idx >= s_settings_errors_entries_count || !s_settings_errors_entries) {
            for (uint16_t col = 0; col < 4; col++) lv_table_set_cell_value(s_settings_errors_log_table, slot, col, "");
            continue;
        }
        const ui_settings_error_entry_t *it = &s_settings_errors_entries[idx];
        lv_table_set_cell_value(s_settings_errors_log_table, slot, 0, it->stamp);
        lv_table_set_cell_value(s_settings_errors_log_table, slot, 1, it->title);
        lv_table_set_cell_value(s_settings_errors_log_table, slot, 2, it->source);
        lv_table_set_cell_value(s_settings_errors_log_table, slot, 3, it->reason);
    }

    lv_obj_set_pos(s_settings_errors_log_table, 0, (lv_coord_t)(s_settings_errors_log_first * row_h));
    s_settings_errors_table_refresh_pending = false;
}

static void ui_settings_errors_scroll_cb(lv_event_t *e) {
    (void)e;
    if (!s_settings_errors_log_list) return;
    int32_t y = -lv_obj_get_scroll_y(s_settings_errors_log_list);
    if (y < 0) y = 0;
    uint16_t first = (uint16_t)(y / ui_settings_errors_row_h());
    const uint16_t max_first = (s_settings_errors_entries_count > SETTINGS_ERRORS_VISIBLE_ROWS)
                                   ? (uint16_t)(s_settings_errors_entries_count - SETTINGS_ERRORS_VISIBLE_ROWS)
                                   : 0;
    if (first > max_first) first = max_first;
    s_settings_errors_log_first = first;
    s_settings_errors_table_refresh_pending = true;
}

static void ui_settings_errors_table_timer_cb(lv_timer_t *t) {
    (void)t;
    if (!s_settings_errors_table_refresh_pending) return;
    ui_settings_errors_refresh_table();
}

static void ui_settings_errors_load_log(void) {
    if (!s_settings_errors_log_list || !s_settings_errors_log_text) return;
    const bool en = ui_is_english();
#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_settings_freeze,
             "errors_load_log: begin entries=%u table=%p",
             (unsigned)s_settings_errors_entries_count,
             (void *)s_settings_errors_log_table);
#endif
    lv_obj_clear_flag(s_settings_errors_log_text, LV_OBJ_FLAG_HIDDEN);
    lv_label_set_text(s_settings_errors_log_text, "");
    s_settings_errors_entries_count = 0;

#if defined(ESP_PLATFORM)
    const char *paths[] = { "/littlefs/logs/events.log", "/littlefs/logs/events.log.1" };
    for (int p = 0; p < 2 && s_settings_errors_entries_count < 256; p++) {
        PP_UI_WDT();
        size_t tail_len = 0;
        char *tail = ui_read_file_tail_alloc(paths[p], 48 * 1024, &tail_len);
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_settings_freeze,
                "errors_load_log: file path=%s tail_len=%u",
                 paths[p],
                 (unsigned)tail_len);
#endif
        if (!tail || tail_len == 0) {
            if (tail) free(tail);
            continue;
        }

        size_t pos = tail_len;
        while (pos > 0 && s_settings_errors_entries_count < 256) {
            size_t end = pos;
            while (pos > 0 && tail[pos - 1] != '\n') pos--;
            size_t start = pos;
            if (start > 0) pos = start - 1;
            else pos = 0;

            size_t ln = end - start;
            if (ln == 0) continue;
            if (ln > 0 && tail[start + ln - 1] == '\r') ln--;
            if (ln == 0) continue;
            if (ln >= 240) continue;

            char tmp[240];
            memcpy(tmp, tail + start, ln);
            tmp[ln] = 0;

            char *sp1 = strchr(tmp, ' ');
            if (!sp1) continue;
            const uint64_t uptime_ms = (uint64_t)strtoull(tmp, NULL, 10);
            char *sp2 = strchr(sp1 + 1, ' ');
            if (!sp2) continue;

            uint64_t unix_s = 0;
            const char *type_ptr = sp1 + 1;
            const char *msg = sp2 + 1;
            bool second_is_number = true;
            for (const char *q = sp1 + 1; q < sp2; q++) {
                if (*q < '0' || *q > '9') {
                    second_is_number = false;
                    break;
                }
            }
            if (second_is_number) {
                unix_s = (uint64_t)strtoull(sp1 + 1, NULL, 10);
                type_ptr = sp2 + 1;
                sp2 = strchr(type_ptr, ' ');
                if (!sp2) continue;
                msg = sp2 + 1;
            }

            char type[20];
            const size_t type_len = (size_t)(sp2 - type_ptr);
            if (type_len == 0 || type_len >= sizeof(type)) continue;
            memcpy(type, type_ptr, type_len);
            type[type_len] = 0;

            if (strcmp(type, "FAULT") != 0 && strcmp(type, "FAULT_CLEAR") != 0) continue;

            const uint32_t code = ui_fault_code_from_log_msg(msg);
            char reason[120];
            ui_fault_reason_from_log_msg(msg, reason, sizeof(reason));
            char stamp[64];
            ui_format_error_log_timestamp(uptime_ms, unix_s, stamp, sizeof(stamp));
            if (!ui_settings_errors_ensure_capacity((uint16_t)(s_settings_errors_entries_count + 1U))) break;
            ui_settings_error_entry_t *dst = &s_settings_errors_entries[s_settings_errors_entries_count++];
            memset(dst, 0, sizeof(*dst));
            lv_snprintf(dst->stamp, sizeof(dst->stamp), "%s", stamp);
            lv_snprintf(dst->reason, sizeof(dst->reason), "%s", reason[0] ? reason : ui_fault_code_text(code));
            lv_snprintf(dst->source, sizeof(dst->source), "%s", ui_fault_source_text(code));
            if (strcmp(type, "FAULT_CLEAR") == 0) {
                lv_snprintf(dst->title, sizeof(dst->title), "%s: %s",
                            ui_is_english() ? "Fault cleared" : "Помилку скинуто",
                            ui_fault_code_text(code));
                dst->is_clear = 1;
            } else {
                lv_snprintf(dst->title, sizeof(dst->title), "%s", ui_fault_code_text(code));
                dst->is_clear = 0;
            }
            dst->code = code;
            PP_UI_SOFT_YIELD();
        }

        free(tail);
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_settings_freeze,
                 "errors_load_log: parsed path=%s count=%d",
                 paths[p],
                (int)s_settings_errors_entries_count);
#endif
        PP_UI_SOFT_YIELD();
    }

    if (s_settings_errors_entries_count <= 0) {
        lv_label_set_text(s_settings_errors_log_text, en ? "Log is empty" : "Лог порожній");
    } else {
        s_settings_errors_log_first = 0;
        s_settings_errors_table_refresh_pending = true;
        ui_settings_errors_refresh_table();
    }
#else
    lv_label_set_text(s_settings_errors_log_text, en ? "N/A" : "N/A");
#endif
#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_settings_freeze,
             "errors_load_log: end count=%u first=%u",
             (unsigned)s_settings_errors_entries_count,
             (unsigned)s_settings_errors_log_first);
#endif
}

static void ui_settings_errors_load_log_async(void *user_data) {
    lv_obj_t *list = (lv_obj_t *)user_data;
    s_settings_errors_log_load_pending = false;
    if (!list || !lv_obj_is_valid(list)) return;
    if (list != s_settings_errors_log_list) return;
    if (!s_settings_errors_root || !lv_obj_is_valid(s_settings_errors_root)) return;
#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_settings_freeze,
             "errors_load_async: enter cur=%d sel=%u root=%p list=%p hidden=%d",
             (int)ui_get_current_screen_id(),
             (unsigned)s_settings_menu_selected,
             (void *)s_settings_errors_root,
             (void *)list,
             lv_obj_has_flag(s_settings_errors_root, LV_OBJ_FLAG_HIDDEN) ? 1 : 0);
#endif
#if defined(ESP_PLATFORM)
    // #region debug-point errors-load-async-before-load
    ESP_LOGI(s_dbg_tag_settings_freeze,
             "errors_load_async: before_load entries=%u pending=%d table=%p",
             (unsigned)s_settings_errors_entries_count,
             s_settings_errors_log_load_pending ? 1 : 0,
             (void *)s_settings_errors_log_table);
    // #endregion
#endif
    ui_settings_errors_load_log();
    if (!s_settings_errors_log_timer) {
        s_settings_errors_log_timer = lv_timer_create(ui_settings_errors_table_timer_cb, 30, NULL);
    }
#if defined(ESP_PLATFORM)
    // #region debug-point errors-load-async-after-load
    ESP_LOGI(s_dbg_tag_settings_freeze,
             "errors_load_async: done cur=%d sel=%u root=%p list=%p root_hidden=%d list_hidden=%d",
             (int)ui_get_current_screen_id(),
             (unsigned)s_settings_menu_selected,
             (void *)s_settings_errors_root,
             (void *)list,
             lv_obj_has_flag(s_settings_errors_root, LV_OBJ_FLAG_HIDDEN) ? 1 : 0,
             lv_obj_has_flag(list, LV_OBJ_FLAG_HIDDEN) ? 1 : 0);
    // #endregion
#endif
}

