static void ui_settings_prepare_placeholder(uint8_t idx, bool ready) {
    if (!s_settings_placeholder_root) return;
    if (!s_settings_placeholder_lbl) return;
    lv_obj_clear_flag(s_settings_placeholder_root, LV_OBJ_FLAG_HIDDEN);
    if (ready) {
        lv_obj_add_flag(s_settings_placeholder_lbl, LV_OBJ_FLAG_HIDDEN);
        return;
    }
    lv_obj_clear_flag(s_settings_placeholder_lbl, LV_OBJ_FLAG_HIDDEN);
    if (idx == 5) lv_label_set_text(s_settings_placeholder_lbl, ui_is_english() ? "Loading..." : "Завантаження...");
    else if (idx == 4) lv_label_set_text(s_settings_placeholder_lbl, ui_is_english() ? "Loading history..." : "Завантаження історії...");
    else if (idx == 3) lv_label_set_text(s_settings_placeholder_lbl, ui_is_english() ? "Loading errors..." : "Завантаження помилок...");
    else if (idx == 1) lv_label_set_text(s_settings_placeholder_lbl, ui_is_english() ? "Loading info..." : "Завантаження інфо...");
    else lv_label_set_text(s_settings_placeholder_lbl, ui_is_english() ? "Loading..." : "Завантаження...");
}

static void ui_settings_activate_section_ui(uint8_t idx) {
    const bool show_display = (idx == 0);
    if (s_settings_display_card1 && lv_obj_is_valid(s_settings_display_card1)) {
        if (show_display) lv_obj_clear_flag(s_settings_display_card1, LV_OBJ_FLAG_HIDDEN);
    }
    if (s_settings_display_card2 && lv_obj_is_valid(s_settings_display_card2)) {
        if (show_display) lv_obj_clear_flag(s_settings_display_card2, LV_OBJ_FLAG_HIDDEN);
    }
    if (s_settings_display_card3 && lv_obj_is_valid(s_settings_display_card3)) {
        if (show_display) lv_obj_clear_flag(s_settings_display_card3, LV_OBJ_FLAG_HIDDEN);
    }
    if (idx == 2 && s_settings_general_root && lv_obj_is_valid(s_settings_general_root)) {
        lv_obj_clear_flag(s_settings_general_root, LV_OBJ_FLAG_HIDDEN);
        ui_settings_update_temp_unit_buttons();
        ui_settings_update_date_format_buttons();
        ui_settings_update_time_format_buttons();
    }
    if (idx == 1 && s_settings_info_root && lv_obj_is_valid(s_settings_info_root)) {
        lv_obj_clear_flag(s_settings_info_root, LV_OBJ_FLAG_HIDDEN);
    }
    if (idx == 3 && s_settings_errors_root && lv_obj_is_valid(s_settings_errors_root)) {
        lv_obj_add_flag(s_settings_errors_root, LV_OBJ_FLAG_SCROLLABLE);
        lv_obj_set_scrollbar_mode(s_settings_errors_root, LV_SCROLLBAR_MODE_AUTO);
        lv_obj_clear_flag(s_settings_errors_root, LV_OBJ_FLAG_HIDDEN);
        lv_obj_scroll_to_y(s_settings_errors_root, 0, LV_ANIM_OFF);
        if (s_settings_errors_reset_btn && lv_obj_is_valid(s_settings_errors_reset_btn)) {
            lv_obj_clear_flag(s_settings_errors_reset_btn, LV_OBJ_FLAG_HIDDEN);
        }
        if (s_settings_errors_log_refresh_btn && lv_obj_is_valid(s_settings_errors_log_refresh_btn)) {
            lv_obj_clear_flag(s_settings_errors_log_refresh_btn, LV_OBJ_FLAG_HIDDEN);
        }
    }
    if (idx == 4 && s_settings_history_root && lv_obj_is_valid(s_settings_history_root)) {
        lv_obj_clear_flag(s_settings_history_root, LV_OBJ_FLAG_HIDDEN);
        if (s_settings_history_list && lv_obj_is_valid(s_settings_history_list)) {
            lv_obj_add_flag(s_settings_history_list, LV_OBJ_FLAG_SCROLLABLE);
            lv_obj_set_scrollbar_mode(s_settings_history_list, LV_SCROLLBAR_MODE_AUTO);
            lv_obj_scroll_to_y(s_settings_history_list, 0, LV_ANIM_OFF);
        }
        ui_settings_history_show_list();
    }
    if (idx == 5 && s_settings_kiln_calib_root && lv_obj_is_valid(s_settings_kiln_calib_root)) {
        lv_obj_add_flag(s_settings_kiln_calib_root, LV_OBJ_FLAG_SCROLLABLE);
        lv_obj_set_scrollbar_mode(s_settings_kiln_calib_root, LV_SCROLLBAR_MODE_AUTO);
        lv_obj_clear_flag(s_settings_kiln_calib_root, LV_OBJ_FLAG_HIDDEN);
        lv_obj_scroll_to_y(s_settings_kiln_calib_root, 0, LV_ANIM_OFF);
    }
}

static void ui_settings_request_section_build(uint8_t idx) {
    if (idx == 1 && !s_settings_info_root && s_settings_placeholder_root && !s_settings_info_build_pending) {
        s_settings_info_build_pending = true;
        (void)lv_async_call(ui_settings_ensure_info_created_async, s_settings_placeholder_root);
    }
    if (idx == 3) {
        if (s_settings_errors_action_msg) lv_obj_add_flag(s_settings_errors_action_msg, LV_OBJ_FLAG_HIDDEN);
        s_settings_errors_action_until_ms = 0;
        ui_settings_update_errors_text();
        if (s_settings_errors_log_text) {
            lv_label_set_text(s_settings_errors_log_text, ui_is_english() ? "Loading..." : "Завантаження...");
        }
        if (!s_settings_errors_log_load_pending && s_settings_errors_log_list) {
            s_settings_errors_log_load_pending = true;
            (void)lv_async_call(ui_settings_errors_load_log_async, s_settings_errors_log_list);
        }
    }
    if (idx == 4 && !s_settings_history_build_pending) {
        s_settings_history_build_pending = true;
        (void)lv_async_call(ui_settings_history_load_list_async, s_settings_history_list);
    }
    if (idx == 5 && !s_settings_kiln_calib_built && s_settings_kiln_calib_root && !s_settings_kiln_calib_build_pending) {
        s_settings_kiln_calib_build_stage = 0;
        s_settings_pid_low_card = NULL;
        s_settings_pid_high_card = NULL;
        s_settings_ssr_card = NULL;
        s_settings_autotune_card = NULL;
        s_settings_ssr_test_status = NULL;
        s_settings_ssr_test_btn = NULL;
        s_settings_ssr_test_btn_label = NULL;
        s_settings_pid_autotune_status = NULL;
        s_settings_pid_autotune_btn = NULL;
        s_settings_pid_autotune_btn_label = NULL;
        s_settings_kiln_calib_build_pending = true;
        (void)lv_async_call(ui_settings_build_kiln_calibration_async, s_settings_kiln_calib_root);
    }
}

static void ui_settings_try_activate_requested_section(void) {
    if (!s_settings_section_open) return;
    if (s_settings_section_requested > 5) return;
    const uint8_t idx = s_settings_section_requested;
    const bool ready = ui_settings_section_is_ready(idx);
    ui_settings_prepare_placeholder(idx, ready);
    if (!ready) return;
    if (s_settings_section_active == idx) return;
    ui_settings_hide_all_sections();
    ui_settings_activate_section_ui(idx);
    s_settings_section_active = idx;
    if (s_settings_placeholder_root && lv_obj_is_valid(s_settings_placeholder_root)) {
        lv_obj_add_flag(s_settings_placeholder_root, LV_OBJ_FLAG_HIDDEN);
    }
}

static void ui_settings_set_section(uint8_t idx) {
    if (idx > 5) idx = 0;
#if defined(ESP_PLATFORM)
    action_close_transient_overlays();
#endif
    lv_indev_t *indev = lv_indev_active();
    if (indev) {
        lv_indev_stop_processing(indev);
        lv_indev_wait_release(indev);
        lv_indev_reset(indev, NULL);
    }
    lv_indev_reset(NULL, NULL);
    lv_anim_del_all();
#if defined(ESP_PLATFORM)
    s_dbg_settings_calib_trace_ticks_left = 0;
    // #region debug-point settings-history-wdt-set-section
    ESP_LOGI(s_dbg_tag_settings_freeze,
             "set_section: idx=%u cur=%d section_open=%d act=%p history_root=%p history_built=%d history_pending=%d history_list=%p placeholder=%p",
             (unsigned)idx,
             (int)ui_get_current_screen_id(),
             s_settings_section_open ? 1 : 0,
             (void *)lv_scr_act(),
             (void *)s_settings_history_root,
             s_settings_history_built ? 1 : 0,
             s_settings_history_build_pending ? 1 : 0,
             (void *)s_settings_history_list,
             (void *)s_settings_placeholder_root);
    // #endregion
    action_debug_dump_overlay_state("settings:set_section:after_reset");
#endif
    s_settings_menu_selected = idx;
    ui_settings_sync_title();
    for (int i = 0; i < 6; i++) {
        if (!s_settings_menu_btns[i]) continue;
        const bool sel = (i == (int)idx);
        lv_obj_clear_state(s_settings_menu_btns[i], LV_STATE_CHECKED | LV_STATE_FOCUSED | LV_STATE_PRESSED);
        if (sel) {
            lv_obj_add_state(s_settings_menu_btns[i], LV_STATE_CHECKED);
        }
    }

    if (s_settings_panel_title) {
        const char *items_ua[] = { "ДИСПЛЕЙ", "ІНФО", "ОСНОВНІ", "ПОМИЛКИ", "ІСТОРІЯ", "КАЛІБРУВАННЯ ПЕЧІ" };
        const char *items_en[] = { "DISPLAY", "INFO", "GENERAL", "ERRORS", "HISTORY", "KILN CALIBRATION" };
        lv_label_set_text(s_settings_panel_title, ui_is_english() ? items_en[idx] : items_ua[idx]);
        if (idx == 0 || idx == 2 || idx == 3 || idx == 4 || idx == 5) lv_obj_add_flag(s_settings_panel_title, LV_OBJ_FLAG_HIDDEN);
        else lv_obj_clear_flag(s_settings_panel_title, LV_OBJ_FLAG_HIDDEN);
    }

    ui_settings_hide_all_sections();
    s_settings_section_active = 0xffu;
    s_settings_section_requested = idx;
    ui_settings_request_section_build(idx);
    ui_settings_prepare_placeholder(idx, ui_settings_section_is_ready(idx));
    ui_settings_try_activate_requested_section();
}

