        lv_obj_set_style_border_width(card, 1, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_radius(card, 10, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_pad_all(card, 14, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_clear_flag(card, LV_OBJ_FLAG_SCROLLABLE);

        lv_obj_t *t = lv_label_create(card);
        lv_obj_set_pos(t, 0, 0);
        lv_obj_set_style_text_font(t, &font_4305a60a491c803d80080d0337447350, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_color(t, lv_color_hex(0xffffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
