        lv_obj_set_size(b_minus, 72, 56);
        lv_obj_set_style_bg_color(b_minus, lv_color_hex(0xff090c10), LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_bg_opa(b_minus, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_border_color(b_minus, lv_color_hex(0xff1c2538), LV_PART_MAIN | LV_STATE_DEFAULT);
