void tick_screen__2() {
    if (!s_main2_time_lbl) return;
    ui_update_header_clock(s_main2_time_lbl, &s_main2_last_clock_update_ms, s_main2_last_clock_text,
                           sizeof(s_main2_last_clock_text));
    ui_update_current_temp(s_main2_current_temp_value_lbl, s_main2_current_temp_unit_lbl, s_main2_current_temp_line_lbl,
                           &s_main2_last_temp_update_ms, s_main2_last_temp_text, sizeof(s_main2_last_temp_text), &s_main2_last_temp_error);
    if (s_main2_last_temp_error) {
        if (s_main2_target_temp_value_lbl) lv_obj_add_flag(s_main2_target_temp_value_lbl, LV_OBJ_FLAG_HIDDEN);
        if (s_main2_heating_rate_value_lbl) lv_obj_add_flag(s_main2_heating_rate_value_lbl, LV_OBJ_FLAG_HIDDEN);
    } else {
        if (s_main2_target_temp_value_lbl) lv_obj_clear_flag(s_main2_target_temp_value_lbl, LV_OBJ_FLAG_HIDDEN);
        if (s_main2_heating_rate_value_lbl) lv_obj_clear_flag(s_main2_heating_rate_value_lbl, LV_OBJ_FLAG_HIDDEN);
        ui_update_target_and_rate(s_main2_target_temp_value_lbl, s_main2_heating_rate_value_lbl, NULL, &s_main2_last_targets_update_ms,
                                  s_main2_last_target_text, sizeof(s_main2_last_target_text), s_main2_last_rate_text, sizeof(s_main2_last_rate_text));
    }
}


