#if defined(ESP_PLATFORM) && defined(CONFIG_IDF_TARGET_ESP32S3)
static void ui_s3_set_header_icon_zoom(lv_obj_t *img, lv_coord_t header_btn) {
    if (!img) return;
    const lv_coord_t target = (lv_coord_t)LV_MAX(16, header_btn - 16);
    uint16_t zoom = (uint16_t)((uint32_t)target * 256u / 32u);
    if (zoom < 96) zoom = 96;
    if (zoom > 256) zoom = 256;
    lv_img_set_zoom(img, zoom);
}

static void ui_s3_align_header(lv_obj_t *screen,
                              lv_obj_t *logo_panel,
                              lv_obj_t *app_name_lbl,
                              lv_obj_t *time_lbl,
                              lv_obj_t *wifi_btn, lv_obj_t *wifi_img,
                              lv_obj_t *lang_panel, lv_obj_t *lang_lbl,
                              lv_obj_t *settings_btn, lv_obj_t *settings_img) {
    if (!screen) return;
    lv_coord_t sw = 0;
    lv_coord_t sh = 0;
    ui_target_display_size(&sw, &sh);
    if (sw <= 0 || sh <= 0) return;

    const int32_t zoom_w = ((int32_t)sw * 256) / 800;
    const int32_t zoom_h = ((int32_t)sh * 256) / 480;
    const int32_t zoom_256 = (zoom_w < zoom_h) ? zoom_w : zoom_h;

    const lv_coord_t margin = (lv_coord_t)((8 * zoom_256) / 256);
    const lv_coord_t gap = (lv_coord_t)((8 * zoom_256) / 256);
    const lv_coord_t header_btn = (lv_coord_t)((56 * zoom_256) / 256);
    const lv_coord_t header_center_y = (lv_coord_t)(margin + header_btn / 2);

    lv_obj_update_layout(screen);

    if (settings_btn) {
        lv_obj_set_size(settings_btn, header_btn, header_btn);
        lv_obj_set_pos(settings_btn, (lv_coord_t)(sw - margin - header_btn), (lv_coord_t)(header_center_y - header_btn / 2));
        lv_obj_set_style_pad_all(settings_btn, 0, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_border_width(settings_btn, 0, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_bg_opa(settings_btn, LV_OPA_TRANSP, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_clear_flag(settings_btn, LV_OBJ_FLAG_SCROLLABLE);
        lv_obj_clear_flag(settings_btn, LV_OBJ_FLAG_HIDDEN);
        if (settings_img) {
            ui_s3_set_header_icon_zoom(settings_img, header_btn);
            lv_obj_center(settings_img);
            lv_obj_clear_flag(settings_img, LV_OBJ_FLAG_HIDDEN);
        }
    }

    if (wifi_btn) {
        lv_obj_set_size(wifi_btn, header_btn, header_btn);
        lv_obj_set_pos(wifi_btn, (lv_coord_t)(sw - margin - header_btn - gap - header_btn), (lv_coord_t)(header_center_y - header_btn / 2));
        lv_obj_set_style_pad_all(wifi_btn, 0, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_border_width(wifi_btn, 0, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_bg_opa(wifi_btn, LV_OPA_TRANSP, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_clear_flag(wifi_btn, LV_OBJ_FLAG_SCROLLABLE);
        lv_obj_clear_flag(wifi_btn, LV_OBJ_FLAG_HIDDEN);
        if (wifi_img) {
            ui_s3_set_header_icon_zoom(wifi_img, header_btn);
            lv_obj_center(wifi_img);
            lv_obj_clear_flag(wifi_img, LV_OBJ_FLAG_HIDDEN);
        }
    }

    if (lang_panel) {
        const lv_coord_t lang_w = (lv_coord_t)LV_MAX(header_btn, (lv_coord_t)((64 * zoom_256) / 256));
        lv_obj_set_size(lang_panel, lang_w, header_btn);
        lv_obj_set_pos(lang_panel, (lv_coord_t)(sw - margin - header_btn - gap - header_btn - gap - lang_w),
                       (lv_coord_t)(header_center_y - header_btn / 2));
        lv_obj_clear_flag(lang_panel, LV_OBJ_FLAG_SCROLLABLE);
        lv_obj_clear_flag(lang_panel, LV_OBJ_FLAG_HIDDEN);
        if (lang_lbl) {
            lv_obj_set_style_text_font(lang_lbl, &font_4305a60a491c803d80080d05cbb3cac2, LV_PART_MAIN | LV_STATE_DEFAULT);
            lv_obj_center(lang_lbl);
        }
        if (lang_lbl) lv_obj_clear_flag(lang_lbl, LV_OBJ_FLAG_HIDDEN);
    }

    if (logo_panel) {
        const lv_coord_t logo_sz = (lv_coord_t)LV_MAX(26, header_btn - 8);
        lv_obj_set_size(logo_panel, logo_sz, logo_sz);
        lv_obj_set_pos(logo_panel, margin, (lv_coord_t)(header_center_y - logo_sz / 2));
        lv_obj_clear_flag(logo_panel, LV_OBJ_FLAG_HIDDEN);
    }

    if (app_name_lbl) {
        lv_obj_set_style_text_font(app_name_lbl, &font_4305a60a491c803d80080d0337447350, LV_PART_MAIN | LV_STATE_DEFAULT);
        const lv_coord_t x = (lv_coord_t)((64 * zoom_256) / 256);
        lv_obj_update_layout(app_name_lbl);
        lv_obj_set_pos(app_name_lbl, x, (lv_coord_t)(header_center_y - lv_obj_get_height(app_name_lbl) / 2));
        lv_obj_clear_flag(app_name_lbl, LV_OBJ_FLAG_HIDDEN);
    }

    if (time_lbl) {
        lv_obj_set_style_text_font(time_lbl, &font_4305a60a491c803d80080d05cbb3cac2, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_color(time_lbl, lv_color_hex(0xffffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_update_layout(time_lbl);
        lv_obj_align(time_lbl, LV_ALIGN_TOP_MID, 0, (lv_coord_t)(header_center_y - lv_obj_get_height(time_lbl) / 2));
        lv_obj_clear_flag(time_lbl, LV_OBJ_FLAG_HIDDEN);
    }
}
#endif

