void tick_screen_wifi_settings() {
    if (!objects.wifi_settings) return;
    if (!s_wifi_info_status || !s_wifi_info_line1) return;

    ui_update_header_clock(s_wifi_settings_time_lbl, &s_wifi_settings_last_clock_update_ms, s_wifi_settings_last_clock_text,
                           sizeof(s_wifi_settings_last_clock_text));

    const bool user_enabled = wifi_is_user_enabled();
    const bool connected = wifi_is_connected();
    const bool ap_active = wifi_ap_active();

    char url[48] = {0};
    wifi_get_server_url_c(url, (int32_t)sizeof(url));
    char ssid[40] = {0};
    wifi_get_ap_ssid_c(ssid, (int32_t)sizeof(ssid));
    char home_ssid[40] = {0};
    wifi_get_sta_ssid_c(home_ssid, (int32_t)sizeof(home_ssid));

    const bool is_en = ui_is_english();
    char status_text[48];
    char line1[64];
    char line2[96];
    lv_color_t status_col = lv_color_hex(0xff7a8b9e);

    if (!user_enabled) {
        lv_snprintf(status_text, sizeof(status_text), "%s", is_en ? "Status: OFF" : "Статус: ВИМКНЕНО");
        status_col = lv_color_hex(0xff7a8b9e);
        lv_snprintf(line1, sizeof(line1), "AP: %s", ssid);
        lv_snprintf(line2, sizeof(line2), "%s %s", is_en ? "Open:" : "Відкрити:", url);
    } else if (connected) {
        lv_snprintf(status_text, sizeof(status_text), "%s", is_en ? "Status: CONNECTED" : "Статус: ПІДКЛЮЧЕНО");
        status_col = lv_color_hex(0xff00b761);
        if (home_ssid[0]) {
            strncpy(line1, home_ssid, sizeof(line1) - 1);
            line1[sizeof(line1) - 1] = '\0';
        } else {
            strncpy(line1, is_en ? "(unknown)" : "(невідомо)", sizeof(line1) - 1);
            line1[sizeof(line1) - 1] = '\0';
        }
        lv_snprintf(line2, sizeof(line2), "%s %s", is_en ? "Web:" : "Веб:", url);
    } else {
        lv_snprintf(status_text, sizeof(status_text), "%s", is_en ? "Status: SETUP" : "Статус: НАЛАШТУВАННЯ");
        status_col = lv_color_hex(0xffffb300);
        lv_snprintf(line1, sizeof(line1), "AP: %s", ssid);
        lv_snprintf(line2, sizeof(line2), "%s %s", is_en ? "Open:" : "Відкрити:", url);
    }

    if (strncmp(s_wifi_last_status_text, status_text, sizeof(s_wifi_last_status_text) - 1) != 0) {
        strncpy(s_wifi_last_status_text, status_text, sizeof(s_wifi_last_status_text) - 1);
        s_wifi_last_status_text[sizeof(s_wifi_last_status_text) - 1] = '\0';
        lv_label_set_text(s_wifi_info_status, s_wifi_last_status_text);
    }
    if ((user_enabled != s_wifi_last_user_enabled) || (connected != s_wifi_last_connected)) {
        lv_obj_set_style_text_color(s_wifi_info_status, status_col, LV_PART_MAIN | LV_STATE_DEFAULT);
    }

    if (strncmp(s_wifi_last_line1, line1, sizeof(s_wifi_last_line1) - 1) != 0) {
        strncpy(s_wifi_last_line1, line1, sizeof(s_wifi_last_line1) - 1);
        s_wifi_last_line1[sizeof(s_wifi_last_line1) - 1] = '\0';
        lv_label_set_text(s_wifi_info_line1, s_wifi_last_line1);
    }
    if (s_wifi_info_line2) {
        if (strncmp(s_wifi_last_line2, line2, sizeof(s_wifi_last_line2) - 1) != 0) {
            strncpy(s_wifi_last_line2, line2, sizeof(s_wifi_last_line2) - 1);
            s_wifi_last_line2[sizeof(s_wifi_last_line2) - 1] = '\0';
            lv_label_set_text(s_wifi_info_line2, s_wifi_last_line2);
        }
    }

    if (s_wifi_web_url) {
        if (strncmp(s_wifi_last_url, url, sizeof(s_wifi_last_url) - 1) != 0) {
            strncpy(s_wifi_last_url, url, sizeof(s_wifi_last_url) - 1);
            s_wifi_last_url[sizeof(s_wifi_last_url) - 1] = '\0';
            lv_label_set_text(s_wifi_web_url, s_wifi_last_url);
        }
    }

    if (s_wifi_toggle_btn && s_wifi_toggle_lbl) {
        const char *toggle = is_en ? (user_enabled ? "ON" : "OFF") : (user_enabled ? "УВІМКНЕНО" : "ВИМКНЕНО");
        if (strncmp(s_wifi_last_toggle, toggle, sizeof(s_wifi_last_toggle) - 1) != 0) {
            strncpy(s_wifi_last_toggle, toggle, sizeof(s_wifi_last_toggle) - 1);
            s_wifi_last_toggle[sizeof(s_wifi_last_toggle) - 1] = '\0';
            lv_label_set_text(s_wifi_toggle_lbl, s_wifi_last_toggle);
        }
        if (user_enabled != s_wifi_last_user_enabled) {
            lv_obj_set_style_bg_color(s_wifi_toggle_btn, lv_color_hex(user_enabled ? 0xff00b761 : 0xffff3b30), LV_PART_MAIN | LV_STATE_DEFAULT);
            lv_obj_set_style_text_color(s_wifi_toggle_lbl, lv_color_hex(0xffffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
        }
    }

    if (s_wifi_change_lbl) {
        const char *change = is_en ? (connected ? "Change network" : "Connect to network")
                                   : (connected ? "ЗМІНИТИ МЕРЕЖУ" : "ПІДКЛЮЧИТИСЯ ДО МЕРЕЖІ");
        if (strncmp(s_wifi_last_change, change, sizeof(s_wifi_last_change) - 1) != 0) {
            strncpy(s_wifi_last_change, change, sizeof(s_wifi_last_change) - 1);
            s_wifi_last_change[sizeof(s_wifi_last_change) - 1] = '\0';
            lv_label_set_text(s_wifi_change_lbl, s_wifi_last_change);
        }
    }

    if (s_wifi_ap_badge) {
        if (ap_active != s_wifi_last_ap_active) {
            lv_obj_set_style_bg_color(s_wifi_ap_badge, lv_color_hex(ap_active ? 0xff12301d : 0xff421212), LV_PART_MAIN | LV_STATE_DEFAULT);
            lv_obj_set_style_border_color(s_wifi_ap_badge, lv_color_hex(ap_active ? 0xff00b761 : 0xffff3b30), LV_PART_MAIN | LV_STATE_DEFAULT);
        }
    }
    if (s_wifi_ap_badge_txt) {
        if (ap_active != s_wifi_last_ap_active) {
            lv_obj_set_style_text_color(s_wifi_ap_badge_txt, lv_color_hex(ap_active ? 0xff00b761 : 0xffff3b30), LV_PART_MAIN | LV_STATE_DEFAULT);
        }
        const char *badge_txt = (ap_active && ssid[0]) ? ssid : (is_en ? "DISABLED" : "ЗАРАЗ ВИМКНЕНО");
        if (strncmp(s_wifi_last_ap_badge, badge_txt, sizeof(s_wifi_last_ap_badge) - 1) != 0) {
            strncpy(s_wifi_last_ap_badge, badge_txt, sizeof(s_wifi_last_ap_badge) - 1);
            s_wifi_last_ap_badge[sizeof(s_wifi_last_ap_badge) - 1] = '\0';
            lv_label_set_text(s_wifi_ap_badge_txt, s_wifi_last_ap_badge);
        }
    }

    s_wifi_last_user_enabled = user_enabled;
    s_wifi_last_connected = connected;
    s_wifi_last_ap_active = ap_active;
    strncpy(s_wifi_last_ssid, ssid, sizeof(s_wifi_last_ssid) - 1);
    s_wifi_last_ssid[sizeof(s_wifi_last_ssid) - 1] = '\0';
    strncpy(s_wifi_last_home_ssid, home_ssid, sizeof(s_wifi_last_home_ssid) - 1);
    s_wifi_last_home_ssid[sizeof(s_wifi_last_home_ssid) - 1] = '\0';
}



